.darma-loader-darma-custom-682 {
  color: var(--loader-color, #6366f1);
  --loader-secondary-color: var(--loader-secondary-color, #a5b4fc);
  --loader-bg: var(--loader-bg, #ffffff);
width: 45px;
aspect-ratio: .75;
--c:no-repeat linear-gradient(currentColor 0 0);
background:
var(--c) 0% 100%,
var(--c) 50% 100%,
var(--c) 100% 100%;
background-size: 20% 65%;
animation: darma-loader-darma-custom-682-l8 1s infinite linear;
}
@keyframes darma-loader-darma-custom-682-l8 {
16.67% {background-position: 0% 0% ,50% 100%,100% 100%}
33.33% {background-position: 0% 0% ,50% 0% ,100% 100%}
50% {background-position: 0% 0% ,50% 0% ,100% 0% }
66.67% {background-position: 0% 100%,50% 0% ,100% 0% }
83.33% {background-position: 0% 100%,50% 100%,100% 0% }
}

